// Hand-written gRPC types for employee limit and limit template RPCs.
// These are not generated by protoc; they follow the same pattern as the generated files.
package userpb

// EmployeeLimitRequest is used to get employee limits by employee ID.
type EmployeeLimitRequest struct {
	EmployeeId int64 `json:"employee_id"`
}

// SetEmployeeLimitsRequest is used to set employee limits.
type SetEmployeeLimitsRequest struct {
	EmployeeId            int64  `json:"employee_id"`
	MaxLoanApprovalAmount string `json:"max_loan_approval_amount"`
	MaxSingleTransaction  string `json:"max_single_transaction"`
	MaxDailyTransaction   string `json:"max_daily_transaction"`
	MaxClientDailyLimit   string `json:"max_client_daily_limit"`
	MaxClientMonthlyLimit string `json:"max_client_monthly_limit"`
}

// ApplyLimitTemplateRequest is used to apply a named template to an employee.
type ApplyLimitTemplateRequest struct {
	EmployeeId   int64  `json:"employee_id"`
	TemplateName string `json:"template_name"`
}

// EmployeeLimitResponse holds the limit values for an employee.
type EmployeeLimitResponse struct {
	Id                    int64  `json:"id"`
	EmployeeId            int64  `json:"employee_id"`
	MaxLoanApprovalAmount string `json:"max_loan_approval_amount"`
	MaxSingleTransaction  string `json:"max_single_transaction"`
	MaxDailyTransaction   string `json:"max_daily_transaction"`
	MaxClientDailyLimit   string `json:"max_client_daily_limit"`
	MaxClientMonthlyLimit string `json:"max_client_monthly_limit"`
}

// ListLimitTemplatesRequest is an empty request for listing templates.
type ListLimitTemplatesRequest struct{}

// CreateLimitTemplateRequest is used to create a new limit template.
type CreateLimitTemplateRequest struct {
	Name                  string `json:"name"`
	Description           string `json:"description"`
	MaxLoanApprovalAmount string `json:"max_loan_approval_amount"`
	MaxSingleTransaction  string `json:"max_single_transaction"`
	MaxDailyTransaction   string `json:"max_daily_transaction"`
	MaxClientDailyLimit   string `json:"max_client_daily_limit"`
	MaxClientMonthlyLimit string `json:"max_client_monthly_limit"`
}

// LimitTemplateResponse holds a limit template.
type LimitTemplateResponse struct {
	Id                    int64  `json:"id"`
	Name                  string `json:"name"`
	Description           string `json:"description"`
	MaxLoanApprovalAmount string `json:"max_loan_approval_amount"`
	MaxSingleTransaction  string `json:"max_single_transaction"`
	MaxDailyTransaction   string `json:"max_daily_transaction"`
	MaxClientDailyLimit   string `json:"max_client_daily_limit"`
	MaxClientMonthlyLimit string `json:"max_client_monthly_limit"`
}

// ListLimitTemplatesResponse holds a list of limit templates.
type ListLimitTemplatesResponse struct {
	Templates []*LimitTemplateResponse `json:"templates"`
}
